"""
MXFP4-MM: #222 - Pre-compiled AOT FP4 GEMM + preshuffle hybrid.

K=512/K=7168: gemm_a16wfp4_preshuffle (fused bf16->fp4 quant, single kernel)
K=2048: AOT pre-compiled fp4_gemm_cdna4 (BSM=64, BSN=256, mfma32)
K=1536: AOT pre-compiled fp4_gemm_cdna4 (BSM=32, BSN=256, KSPLIT=3)

The AOT kernels were cross-compiled with triton.compile() + GPUTarget("hip","gfx950",64)
in Docker on CPU. They load via Triton runtime — zero JIT compilation.
"""
import os, json, base64, tempfile, ctypes
import torch
import triton
from task import input_t, output_t
from aiter.ops.triton.utils.core import AITER_TRITON_CONFIGS_PATH
from aiter.ops.triton.utils._triton import arch_info
from aiter.ops.triton.quant import dynamic_mxfp4_quant
from aiter.ops.triton.gemm.basic.gemm_a16wfp4 import gemm_a16wfp4_preshuffle

# Preshuffle configs for K=512/K=7168
_PS_CONFIGS = {
    "N=2880-K=512": {
        "M_LEQ_4": {"BLOCK_SIZE_M": 8, "BLOCK_SIZE_N": 128, "BLOCK_SIZE_K": 512, "GROUP_SIZE_M": 1, "NUM_KSPLIT": 1, "num_warps": 4, "num_stages": 1, "waves_per_eu": 1, "matrix_instr_nonkdim": 16, "cache_modifier": ".cg"},
        "M_LEQ_32": {"BLOCK_SIZE_M": 32, "BLOCK_SIZE_N": 64, "BLOCK_SIZE_K": 512, "GROUP_SIZE_M": 1, "NUM_KSPLIT": 1, "num_warps": 4, "num_stages": 1, "waves_per_eu": 2, "matrix_instr_nonkdim": 16, "cache_modifier": ".cg"},
        "any": {"BLOCK_SIZE_M": 32, "BLOCK_SIZE_N": 64, "BLOCK_SIZE_K": 512, "GROUP_SIZE_M": 1, "NUM_KSPLIT": 1, "num_warps": 8, "num_stages": 1, "waves_per_eu": 2, "matrix_instr_nonkdim": 16, "cache_modifier": None}
    },
    "N=4096-K=512": {
        "M_LEQ_32": {"BLOCK_SIZE_M": 32, "BLOCK_SIZE_N": 64, "BLOCK_SIZE_K": 512, "GROUP_SIZE_M": 1, "NUM_KSPLIT": 1, "num_warps": 4, "num_stages": 1, "waves_per_eu": 2, "matrix_instr_nonkdim": 16, "cache_modifier": ".cg"},
        "any": {"BLOCK_SIZE_M": 32, "BLOCK_SIZE_N": 64, "BLOCK_SIZE_K": 512, "GROUP_SIZE_M": 1, "NUM_KSPLIT": 1, "num_warps": 8, "num_stages": 1, "waves_per_eu": 2, "matrix_instr_nonkdim": 16, "cache_modifier": None}
    },
}

def _inject_configs():
    try:
        dev = arch_info.get_arch()
    except Exception:
        dev = "gfx950"
    config_dir = f"{AITER_TRITON_CONFIGS_PATH}/gemm"
    os.makedirs(config_dir, exist_ok=True)
    for shape_key, config in _PS_CONFIGS.items():
        fpath = f"{config_dir}/{dev}-GEMM-A16WFP4_PRESHUFFLED-{shape_key}.json"
        with open(fpath, "w") as f:
            json.dump(config, f)

_inject_configs()


# ============================================================
# AOT KERNEL LOADING
# ============================================================

_K1536_B64 = ""

_K2048_B64 = ""

_K1536_SHARED = 36864
_K2048_SHARED = 82944
_K1536_WARPS = 8
_K2048_WARPS = 8
_KERNEL_NAME = "fp4_gemm_cdna4"

# K=1536 config: BSM=32, BSN=256, BSK=256, KSPLIT=3
# K=2048 config: BSM=64, BSN=256, BSK=512, KSPLIT=2

_aot_kernels = {}  # k_logical -> (module, function, shared, num_warps, config)

def _load_aot_kernels():
    """Load pre-compiled AOT kernels via Triton runtime."""
    import sys
    try:
        drv = triton.runtime.driver.active
        utils = drv.utils
        device = torch.cuda.current_device()

        for k_logical, b64, shared, nw in [
            (1536, _K1536_B64, _K1536_SHARED, _K1536_WARPS),
            (2048, _K2048_B64, _K2048_SHARED, _K2048_WARPS),
        ]:
            binary = base64.b64decode(b64)
            mod, func, n_regs, n_spills, n_max_threads = utils.load_binary(
                _KERNEL_NAME, binary, shared, device
            )
            _aot_kernels[k_logical] = (mod, func, shared, nw)
            print(f"[AOT] Loaded k={k_logical}: regs={n_regs}, spills={n_spills}", file=sys.stderr)
    except Exception as e:
        print(f"[AOT] Failed to load: {e}", file=sys.stderr)

_load_aot_kernels()


def shuffle_scales(scales):
    sm, sn = scales.shape
    scales = scales.view(sm // 32, 2, 16, sn // 8, 2, 4, 1)
    scales = scales.permute(0, 3, 5, 2, 4, 1, 6).contiguous()
    scales = scales.view(sm // 32, sn * 32)
    return scales


def e8m0_unshuffle(scale, orig_m, orig_n):
    sm, sn = scale.shape
    scale = scale.view(sm // 32, sn // 8, 4, 16, 2, 2)
    scale = scale.permute(0, 5, 3, 1, 4, 2).contiguous()
    scale = scale.view(sm, sn)
    return scale[:orig_m, :orig_n]


_ps_cache_key = None
_ps_cache_w = None
_ps_cache_ws = None
_aot_cache_key = None
_aot_cache_vals = None


def _launch_aot(func, shared, num_warps, grid,
                A_q, B_q_t, C, A_scale_sh, B_scale_sh,
                M, N, K_packed,
                stride_am, stride_ak, stride_bk, stride_bn,
                stride_ck, stride_cm, stride_cn,
                stride_asm, stride_ask, stride_bsn, stride_bsk):
    """Launch pre-compiled AOT kernel via Triton's GPU launch."""
    from triton.runtime import driver as _driver
    _driver.active.launcher(func, grid, num_warps, shared, 0,
        A_q, B_q_t, C, A_scale_sh, B_scale_sh,
        M, N, K_packed,
        stride_am, stride_ak, stride_bk, stride_bn,
        stride_ck, stride_cm, stride_cn,
        stride_asm, stride_ask, stride_bsn, stride_bsk,
    )


@torch.inference_mode()
def custom_kernel(data: input_t) -> output_t:
    global _ps_cache_key, _ps_cache_w, _ps_cache_ws
    global _aot_cache_key, _aot_cache_vals
    A, B, B_q, B_shuffle, B_scale_sh = data
    m, k = A.shape
    n = B.shape[0]

    if k <= 512 or k == 7168:
        # Preshuffle: single kernel, fused quant+GEMM
        key = (B_shuffle.data_ptr(), B_scale_sh.data_ptr())
        if key == _ps_cache_key:
            B_w = _ps_cache_w
            B_ws = _ps_cache_ws
        else:
            B_w = B_shuffle.view(torch.uint8).reshape(n // 16, (k // 2) * 16)
            B_ws = B_scale_sh.view(torch.uint8)[:n, :].contiguous().reshape(n // 32, k)
            _ps_cache_key = key
            _ps_cache_w = B_w
            _ps_cache_ws = B_ws
        return gemm_a16wfp4_preshuffle(A, B_w, B_ws, prequant=True, dtype=torch.bfloat16)

    elif k in _aot_kernels:
        # AOT pre-compiled kernel for K=2048/K=1536
        mod, func, shared, nw = _aot_kernels[k]
        B_q_uint8 = B_q.view(torch.uint8)

        # Quant A
        A_q, A_scale = dynamic_mxfp4_quant(A)

        # Shuffle scales for the kernel
        A_scale_sh = shuffle_scales(A_scale)
        key = (B.data_ptr(), B_q.data_ptr(), B_scale_sh.data_ptr())
        if key == _aot_cache_key:
            B_scale_sh_shuffled = _aot_cache_vals
        else:
            B_scale_orig = e8m0_unshuffle(B_scale_sh.view(torch.uint8), n, k // 32)
            B_scale_sh_shuffled = shuffle_scales(B_scale_orig)
            _aot_cache_key = key
            _aot_cache_vals = B_scale_sh_shuffled

        # Transpose B for the kernel (expects K//2 x N)
        B_q_t = B_q_uint8.T.contiguous()

        # Determine config
        if k == 1536:
            BSM, BSN, KSPLIT = 32, 256, 3
            K_packed = k // 2  # 768
            SPLITK_BLOCK_SIZE = 512
        else:  # k == 2048
            BSM, BSN, KSPLIT = 64, 256, 2
            K_packed = k // 2  # 1024
            SPLITK_BLOCK_SIZE = 1024

        grid_mn = triton.cdiv(m, BSM) * triton.cdiv(n, BSN)
        grid = (KSPLIT * grid_mn, 1, 1)

        # Output
        if KSPLIT == 1:
            C = torch.empty((m, n), dtype=torch.bfloat16, device=A.device)
            stride_ck = 0
        else:
            C = torch.empty((KSPLIT, m, n), dtype=torch.float32, device=A.device)
            stride_ck = C.stride(0)

        try:
            _launch_aot(
                func, shared, nw, grid,
                A_q, B_q_t, C, A_scale_sh, B_scale_sh_shuffled,
                m, n, K_packed,
                A_q.stride(0), A_q.stride(1),
                B_q_t.stride(0), B_q_t.stride(1),
                stride_ck,
                C.stride(-2) if KSPLIT > 1 else C.stride(0),
                C.stride(-1) if KSPLIT > 1 else C.stride(1),
                A_scale_sh.stride(0), A_scale_sh.stride(1),
                B_scale_sh_shuffled.stride(0), B_scale_sh_shuffled.stride(1),
            )

            if KSPLIT > 1:
                # Reduce split-K partials
                result = C.sum(dim=0).to(torch.bfloat16)
                return result
            return C
        except Exception as e:
            import sys
            print(f"[AOT] Launch failed: {e}, falling back to preshuffle", file=sys.stderr)

    # Fallback: preshuffle for everything
    key = (B_shuffle.data_ptr(), B_scale_sh.data_ptr())
    if key == _ps_cache_key:
        B_w = _ps_cache_w
        B_ws = _ps_cache_ws
    else:
        B_w = B_shuffle.view(torch.uint8).reshape(n // 16, (k // 2) * 16)
        B_ws = B_scale_sh.view(torch.uint8)[:n, :].contiguous().reshape(n // 32, k)
        _ps_cache_key = key
        _ps_cache_w = B_w
        _ps_cache_ws = B_ws
    return gemm_a16wfp4_preshuffle(A, B_w, B_ws, prequant=True, dtype=torch.bfloat16)
